class Solution:
    def longestSubarray(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        left = 0
        zeros = 0
        max_len = 0

        for right in range(len(nums)):
            if nums[right] == 0:
                zeros += 1

            # Shrink window if more than one zero
            while zeros > 1:
                if nums[left] == 0:
                    zeros -= 1
                left += 1

            # Window has at most one zero, minus 1 for the deleted element
            max_len = max(max_len, right - left)

        return max_len
